import { findAndValidateRecordTimestamp } from "../utils/index.js";
import { getLoggerFor } from "../utils/logUtil.js";
import PagedBucketizer from "./pagedBucketizer.js";
import { TREE, XSD } from "@treecg/types";
import { DataFactory } from "n3";
const { literal, namedNode } = DataFactory;
export default class ReversedPagedBucketizer extends PagedBucketizer {
    logger = getLoggerFor(this);
    constructor(config, save) {
        super(config, save);
    }
    bucketize(record, getBucket, addRelation, removeRelation) {
        const index = Math.floor(this.count / this.pageSize);
        this.count++;
        const currentBucket = getBucket("page-" + index);
        const recordTimestamp = findAndValidateRecordTimestamp(record, this.path, this.lastMemberTimestamp, this.logger);
        if (recordTimestamp === null) {
            return [];
        }
        if (recordTimestamp) {
            this.lastMemberTimestamp = recordTimestamp.getTime();
        }
        if (this.count === 1) {
            const navigatorBucket = getBucket("", true);
            addRelation(navigatorBucket, currentBucket, TREE.terms.Relation);
            this.logger.info("Created first page and navigator buckets");
        }
        else if (this.count % this.pageSize === 1 && this.count > 1) {
            const oldBucket = getBucket("page-" + (index - 1));
            const navigatorBucket = getBucket("", true);
            removeRelation(navigatorBucket, oldBucket, TREE.terms.Relation);
            addRelation(navigatorBucket, currentBucket, TREE.terms.Relation);
            oldBucket.immutable = true;
            if (recordTimestamp) {
                addRelation(currentBucket, oldBucket, TREE.terms.LessThanOrEqualToRelation, literal(recordTimestamp.toISOString(), namedNode(XSD.dateTime)), this.pathQuads);
            }
            else {
                addRelation(currentBucket, oldBucket, TREE.terms.Relation);
            }
            this.logger.info(`Created new page bucket ${index}`);
        }
        return [currentBucket];
    }
    save() {
        return super.save();
    }
}
